VALUES
  ('real-estate-moex-01154', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲被酒醉駕車之乙撞傷住院，甲所駕駛之汽車亦因此受損，下列敘述何者最正確？', '["甲對於汽車所受之損害，僅得請求乙將汽車修復原狀，不得主張修復原狀所必要之費用以代替回復原狀", "甲受傷住院，得因人格權受侵害對乙請求非財產上之損害賠償，其請求之數額限於甲實際所受之損害", "甲對於汽車所受之損害，得對加害人乙請求汽車因毀損所減少之數額", "被害人甲若對第三人負有法定扶養義務者，加害人乙對該第三人亦應負損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01155', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲為幫助清寒家庭學生求學，捐助三千萬元成立A教育基金會，經主管機關許可後，登記為法人，下列 敘述何者最正確？', '["甲之捐助行為為事實行為", "A教育基金會應設董事", "A教育基金會為公益社團法人", "A教育基金會應設總會，作為基金會之最高意思機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01156', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲出租房屋給乙，三天後乙搬入居住，並依約繳交房租，下列敘述何者最正確？', '["關於房屋租金之請求權，其消滅時效期間為兩年", "租賃期間若甲將房屋出賣給丙，甲與乙之租賃關係即消滅", "甲若將房屋贈與丁，並移轉房屋所有權給丁，則乙之租賃契約對丁繼續存在", "甲若先後將房屋出賣給戊與辛，則基於優先性之考量，僅甲與戊之買賣契約生效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01157', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲十八歲，已婚，下列敘述何者最正確？', '["甲已成年", "甲得獨立為有效之單獨行為", "甲授與代理權給乙，其授權行為效力未定", "甲如欲與其配偶兩願離婚，得自行為之，無須得法定代理人之同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01158', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲委任乙處理A土地買賣相關事宜，下列敘述何者最正確？', '["委任人甲得將對乙之處理委任事務請求權讓與第三人", "受任人乙若受有報酬，委任人甲無須因受任人之請求，預付處理委任事務之必要費用", "受任人乙因不可歸責於自己之事由，不得已須在不利於委任人之時期終止契約者，對於委任人甲因此 所受之損害無須付賠償責任", "以上皆為正確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01159', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其對乙之債權讓與給丙，下列敘述何者最正確？', '["甲若未將債權讓與之事由通知乙，則甲與丙間之債權讓與無效", "甲應將證明債權之文件，交付受讓人丙", "債權讓與為負擔行為", "債權讓與時，該債權擔保之最高限額抵押權亦隨同移轉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01160', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將位於忠孝路的一間公寓出租給乙，租期三年，下列敘述何者最正確？', '["乙若遲繳租金，甲應在兩年內請求乙繳納，否則租金請求權將罹於消滅時效", "甲與乙之租賃契約若未經公證，在乙搬入租賃房屋後，縱使甲將租賃物所有權讓與第三人，甲與乙之租 賃契約對於第三人不生效力", "乙搬入租賃房屋居住後，縱使甲將租賃物所有權基於贈與之原因讓與第三人丙，租賃契約對於丙不生效 力，丙得請求乙搬離租屋處並返還房屋", "租賃物之修繕，得因雙方當事人之約定，由承租人負責"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01161', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '乙家中的寵物飼料已吃完，向鄰居甲借用一包飼料供家中寵物食用，並約定隔日還給甲一包相同的新飼 料，下列敘述何者最正確？', '["甲與乙之間成立使用借貸", "甲與乙之借貸契約於雙方意思合致時即為成立", "甲與乙之契約如未約定報償，貸與人甲對於借用物之瑕疵，非因故意而未告知時，對於借用人乙因此所 受之損害無須負損害賠償責任", "借用人不能以種類、品質、數量相同之物返還時，應以借用時，借用地之價值償還"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01162', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲為乙之代理人，下列敘述何者最正確？', '["若甲為意定代理人，其被相對人丙詐欺所為之代理行為，應由甲自行撤銷", "甲逾越代理權限所為之代理行為，得因乙之承認而確定生效", "若甲僅十六歲，甲所為之代理行為無效", "若甲為乙之法定代理人，得因乙之同意，為雙方代理行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01163', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向乙提出給付，但給付遲延，下列敘述何者最正確？', '["乙得向甲主張遲延之損害賠償以代替原定給付", "甲在遲延中，對於因不可抗力而生之損害，原則上毋須負責", "遲延之債務，以支付金錢為標的者，債權人乙得向債務人甲請求以法定利率計算之遲延利息", "對於甲之遲延給付，不論是否可歸責於甲，甲皆應負遲延之賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
